Context.miscCode:
function addExtensionDate(extensionValue,dateString,dateType){
	oneDay  = 24*60*60*1000;
	var extensionDate = null;
	var pivotDate = WPU.getDateObject(dateString,dateType);
	if( null !=pivotDate  && null != extensionValue ){
		var pivotDateMillis = pivotDate.getTime(); 
		var extensionValueMillis = extensionValue*oneDay;
		var extensionDate = new Date(extensionValueMillis+pivotDateMillis);
	}
	
	if( null != extensionDate)
	{ 	var year = extensionDate.getYear();
		var day = extensionDate.getDate();
		if( day < 10) day = "0"+day;
		var mnth = extensionDate.getMonth() + 1;
		if( mnth < 10 ) mnth = "0"+mnth;
		return year + "-" + mnth + "-" + day;
	}
	return "";
}

